import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Systems Technologies","description":"","frontmatter":{"title":"Systems Technologies","parent":"Theory (Paper 2)","nav_order":1,"has_children":true},"headers":[],"relativePath":"theory/systems/index.md","filePath":"theory/systems/index.md"}'),s={name:"theory/systems/index.md"};function n(i,t,d,h,l,m){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="systems-technologies" tabindex="-1">Systems Technologies <a class="header-anchor" href="#systems-technologies" aria-label="Permalink to &quot;Systems Technologies&quot;">​</a></h1><p>Systems Technologies is the foundation of the IT theory curriculum. It covers what computers are made of (hardware), how they are controlled (software and operating systems), how performance is measured and improved, and how modern trends like cloud computing and virtualisation are changing the way we use technology.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./what-is-computing.html">What is Computing?</a></td><td>Definition of a computer, data vs information, the IPO model</td></tr><tr><td><a href="./hardware.html">Hardware</a></td><td>CPU, motherboard, RAM, ROM, storage devices and how they work together</td></tr><tr><td><a href="./peripherals.html">Peripherals</a></td><td>Input, output and storage peripherals; wired vs wireless connections</td></tr><tr><td><a href="./performance.html">Performance</a></td><td>Factors affecting computer performance: clock speed, RAM, cache, cores</td></tr><tr><td><a href="./types-of-computers.html">Types of Computers</a></td><td>Supercomputers, mainframes, desktops, laptops, tablets and embedded systems</td></tr><tr><td><a href="./mobile-tech.html">Mobile Technology</a></td><td>Smartphones, feature phones, PDAs, wearables and mobile OS comparisons</td></tr><tr><td><a href="./software.html">Software</a></td><td>System software, application software, open-source vs proprietary</td></tr><tr><td><a href="./os-management.html">Operating System Management</a></td><td>OS functions, file management, memory management, user interfaces</td></tr><tr><td><a href="./data-representation.html">Data Representation</a></td><td>Binary, hexadecimal, ASCII, Unicode, how data is stored and measured</td></tr><tr><td><a href="./cloud-virtualisation.html">Cloud &amp; Virtualisation</a></td><td>Cloud models (IaaS, PaaS, SaaS), virtualisation concepts, advantages and risks</td></tr></tbody></table><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>Systems Technologies appears in <strong>Paper 2</strong> and is examined across <strong>Grades 10, 11 and 12</strong>.</p><ul><li><strong>Grade 10</strong> — Hardware components, peripherals, types of computers, basic software concepts.</li><li><strong>Grade 11</strong> — Operating system management, performance factors, mobile technology.</li><li><strong>Grade 12</strong> — Cloud computing, virtualisation, advanced OS concepts, data representation.</li></ul>',7)])])}const u=e(s,[["render",n]]);export{p as __pageData,u as default};
